type FileDialogFilter = { name: string; extensions: string[] };

export interface FileDialogResult {
  path: string | null;
}

let _dialogModule: {
  open: (opts?: {
    filters?: FileDialogFilter[];
    multiple?: boolean;
  }) => Promise<FileDialogResult | null>;
  save: (opts?: {
    filters?: FileDialogFilter[];
    defaultPath?: string;
  }) => Promise<string | null>;
} | null = null;

async function getDialog() {
  if (_dialogModule) return _dialogModule;
  try {
    _dialogModule = await import("@tauri-apps/plugin-dialog");
    return _dialogModule;
  } catch {
    return null;
  }
}

/** Open a file picker. Returns null on Android (not supported). */
export async function openDialog(opts?: {
  filters?: FileDialogFilter[];
  multiple?: boolean;
}): Promise<FileDialogResult | null> {
  const dialog = await getDialog();
  if (!dialog) return null;
  return dialog.open(opts);
}

/** Open a save dialog. Returns null on Android (not supported). */
export async function saveDialog(opts?: {
  filters?: FileDialogFilter[];
  defaultPath?: string;
}): Promise<string | null> {
  const dialog = await getDialog();
  if (!dialog) return null;
  return dialog.save(opts);
}

