name = "mysillytavern"
version = "0.1.0"
description = "A Tauri App"
authors = ["you"]
edition = "2021"

# See more keys and their definitions at https://doc.rust-lang.org/cargo/reference/manifest.html

[lib]
# The `_lib` suffix may seem redundant but it is necessary
# to make the lib name unique and wouldn't conflict with the bin name.
# This seems to be only an issue on Windows, see https://github.com/rust-lang/cargo/issues/8519
name = "mysillytavern_lib"
crate-type = ["staticlib", "cdylib", "rlib"]

[features]
default = ["desktop-plugins"]
# tauri-plugin-dialog and tauri-plugin-process are desktop-only;
# Android builds should use --no-default-features to exclude them.
desktop-plugins = ["tauri-plugin-dialog", "tauri-plugin-process"]

[build-dependencies]
